<?php

namespace CreativeCatCo\GkCmsCore\Filament\Resources;

use Filament\Forms;
use Filament\Forms\Form;
use Filament\Forms\Get;
use Filament\Resources\Resource;
use Filament\Tables;
use Filament\Tables\Table;
use CreativeCatCo\GkCmsCore\Models\Page;
use CreativeCatCo\GkCmsCore\Filament\Resources\PageResource\Pages;
use Illuminate\Database\Eloquent\Builder;

class PageResource extends Resource
{
    protected static ?string $model = Page::class;

    protected static ?string $navigationIcon = 'heroicon-o-document-text';

    protected static ?string $navigationGroup = 'Content';

    protected static ?int $navigationSort = 1;

    protected static ?string $recordTitleAttribute = 'title';

    /**
     * Filter the Pages list to only show regular pages and posts.
     * Theme components (header, footer, archive, etc.) are managed in Theme Builder.
     */
    public static function getEloquentQuery(): Builder
    {
        return parent::getEloquentQuery()
            ->where(function (Builder $query) {
                $query->whereIn('page_type', ['page', 'post'])
                      ->orWhereNull('page_type');
            });
    }

    public static function form(Form $form): Form
    {
        return $form
            ->schema([
                // ─── PAGE SETTINGS ───
                Forms\Components\Section::make('Page Settings')
                    ->schema([
                        Forms\Components\TextInput::make('title')
                            ->required()
                            ->maxLength(255)
                            ->live(onBlur: true)
                            ->afterStateUpdated(function (string $operation, $state, Forms\Set $set) {
                                if ($operation === 'create') {
                                    $set('slug', \Illuminate\Support\Str::slug($state));
                                }
                            }),

                        Forms\Components\TextInput::make('slug')
                            ->required()
                            ->maxLength(255)
                            ->unique(ignoreRecord: true)
                            ->rules(['alpha_dash']),

                        Forms\Components\Select::make('page_type')
                            ->label('Page Type')
                            ->options([
                                'page' => 'Page',
                            ])
                            ->default('page')
                            ->required()
                            ->hidden(),

                        Forms\Components\Select::make('template')
                            ->label('Page Template')
                            ->options(fn () => Page::getAvailableTemplates())
                            ->default('custom')
                            ->required()
                            ->live()
                            ->helperText('Custom (AI-Generated) is the default. Use other templates only for hand-coded uploads.')
                            ->columnSpanFull(),

                        Forms\Components\FileUpload::make('featured_image')
                            ->image()
                            ->directory(config('cms.media_upload_path', 'cms/media') . '/pages')
                            ->imageEditor()
                            ->columnSpanFull(),
                    ])
                    ->columns(2),

                // ─── CUSTOM TEMPLATE (AI-GENERATED) ───
                Forms\Components\Section::make('Custom Template Code')
                    ->description('Paste or edit the Blade/HTML template code generated by AI.')
                    ->schema([
                        Forms\Components\Textarea::make('custom_template')
                            ->label('Template Code (Blade/HTML)')
                            ->rows(20)
                            ->columnSpanFull()
                            ->helperText('After saving, the system will auto-discover editable fields from your template code.'),
                    ])
                    ->visible(fn (Get $get) => $get('template') === 'custom')
                    ->collapsible(),

                // ─── EDITABLE FIELDS (auto-generated from field definitions) ───
                Forms\Components\Section::make('Editable Content')
                    ->description('These fields are defined by the page template. Edit values here and they will appear on the live page.')
                    ->schema(function (Get $get, ?Page $record): array {
                        if (!$record || !$record->hasFields()) {
                            return [
                                Forms\Components\Placeholder::make('no_fields')
                                    ->label('')
                                    ->content('No editable fields defined yet. Save a custom template with data-field attributes, or add field definitions manually.')
                                    ->columnSpanFull(),
                            ];
                        }

                        return static::buildFieldsForm($record);
                    })
                    ->visible(fn (?Page $record) => $record !== null)
                    ->collapsible(),

                // ─── FIELD DEFINITIONS MANAGER ───
                Forms\Components\Section::make('Field Definitions')
                    ->description('Manage the editable field schema for this page. Fields are auto-discovered from the template.')
                    ->schema([
                        Forms\Components\Repeater::make('field_definitions')
                            ->label('')
                            ->schema([
                                Forms\Components\TextInput::make('key')
                                    ->label('Field Key')
                                    ->required()
                                    ->rules(['alpha_dash'])
                                    ->placeholder('hero_headline'),

                                Forms\Components\TextInput::make('label')
                                    ->label('Display Label')
                                    ->required()
                                    ->placeholder('Hero Headline'),

                                Forms\Components\Select::make('type')
                                    ->label('Field Type')
                                    ->options(Page::FIELD_TYPES)
                                    ->required()
                                    ->default('text'),

                                Forms\Components\TextInput::make('group')
                                    ->label('Group')
                                    ->placeholder('Hero Section')
                                    ->default('General'),

                                Forms\Components\TextInput::make('placeholder')
                                    ->label('Placeholder')
                                    ->placeholder('Enter your headline...'),

                                Forms\Components\TextInput::make('order')
                                    ->label('Sort Order')
                                    ->numeric()
                                    ->default(0),
                            ])
                            ->columns(3)
                            ->collapsible()
                            ->cloneable()
                            ->reorderable()
                            ->itemLabel(fn (array $state): ?string => ($state['label'] ?? 'Field') . ' (' . ($state['type'] ?? 'text') . ')')
                            ->columnSpanFull(),
                    ])
                    ->collapsible()
                    ->collapsed(),

                // ─── LEGACY RICH TEXT CONTENT ───
                Forms\Components\Section::make('Rich Text Content (Legacy)')
                    ->description('Use this only if you are not using custom templates with editable fields.')
                    ->schema([
                        Forms\Components\RichEditor::make('content')
                            ->label('Content')
                            ->fileAttachmentsDirectory(config('cms.media_upload_path', 'cms/media'))
                            ->columnSpanFull(),
                    ])
                    ->collapsible()
                    ->collapsed(),

                // ─── PAGE-SPECIFIC CSS ───
                Forms\Components\Section::make('Custom CSS')
                    ->description('Add CSS that applies only to this page.')
                    ->schema([
                        Forms\Components\Textarea::make('custom_css')
                            ->label('Page CSS')
                            ->rows(8)
                            ->columnSpanFull()
                            ->helperText('This CSS will be injected into the <head> of this page only.'),
                    ])
                    ->collapsible()
                    ->collapsed(),

                // ─── STATUS & ORDERING ───
                Forms\Components\Section::make('Status & Ordering')
                    ->schema([
                        Forms\Components\Select::make('status')
                            ->options([
                                'draft' => 'Draft',
                                'published' => 'Published',
                            ])
                            ->required()
                            ->default('draft'),

                        Forms\Components\TextInput::make('sort_order')
                            ->numeric()
                            ->default(0),
                    ])
                    ->columns(2),

                // ─── SEO ───
                Forms\Components\Section::make('SEO')
                    ->schema([
                        Forms\Components\TextInput::make('seo_title')
                            ->label('SEO Title')
                            ->maxLength(70)
                            ->helperText('Leave blank to use page title'),

                        Forms\Components\Textarea::make('seo_description')
                            ->label('Meta Description')
                            ->maxLength(160)
                            ->rows(3),

                        Forms\Components\FileUpload::make('og_image')
                            ->label('Social Share Image')
                            ->image()
                            ->directory(config('cms.media_upload_path', 'cms/media') . '/seo'),
                    ])
                    ->collapsible()
                    ->collapsed(),
            ]);
    }

    /**
     * Dynamically build Filament form components from the page's field definitions.
     */
    protected static function buildFieldsForm(Page $page): array
    {
        $components = [];
        $grouped = $page->getGroupedFieldDefinitions();

        foreach ($grouped as $groupName => $definitions) {
            $groupComponents = [];

            foreach ($definitions as $def) {
                $key = 'fields.' . $def['key'];
                $label = $def['label'] ?? Page::keyToLabel($def['key']);
                $type = $def['type'] ?? 'text';
                $placeholder = $def['placeholder'] ?? '';

                $component = match ($type) {
                    'textarea' => Forms\Components\Textarea::make($key)
                        ->label($label)
                        ->placeholder($placeholder)
                        ->rows(3)
                        ->columnSpanFull(),

                    'richtext' => Forms\Components\RichEditor::make($key)
                        ->label($label)
                        ->fileAttachmentsDirectory(config('cms.media_upload_path', 'cms/media'))
                        ->columnSpanFull(),

                    'image' => Forms\Components\FileUpload::make($key)
                        ->label($label)
                        ->image()
                        ->directory(config('cms.media_upload_path', 'cms/media'))
                        ->imageEditor()
                        ->imagePreviewHeight('150')
                        ->columnSpanFull(),

                    'url' => Forms\Components\TextInput::make($key)
                        ->label($label)
                        ->placeholder($placeholder ?: 'https://'),

                    'color' => Forms\Components\ColorPicker::make($key)
                        ->label($label),

                    'select' => Forms\Components\Select::make($key)
                        ->label($label)
                        ->options($def['options'] ?? []),

                    'number' => Forms\Components\TextInput::make($key)
                        ->label($label)
                        ->numeric()
                        ->placeholder($placeholder),

                    'toggle' => Forms\Components\Toggle::make($key)
                        ->label($label),

                    'button' => Forms\Components\Fieldset::make($label)
                        ->schema([
                            Forms\Components\TextInput::make($key . '.text')
                                ->label('Button Text')
                                ->placeholder('Click Here'),
                            Forms\Components\TextInput::make($key . '.link')
                                ->label('Button Link')
                                ->placeholder('/contact'),
                            Forms\Components\Select::make($key . '.style')
                                ->label('Button Style')
                                ->options([
                                    'primary' => 'Primary (filled)',
                                    'secondary' => 'Secondary (outline)',
                                    'accent' => 'Accent (highlight)',
                                ])
                                ->default('primary'),
                            Forms\Components\Toggle::make($key . '.visible')
                                ->label('Visible')
                                ->default(true),
                        ])
                        ->columns(4)
                        ->columnSpanFull(),

                    'button_group' => Forms\Components\Repeater::make($key)
                        ->label($label)
                        ->schema([
                            Forms\Components\TextInput::make('text')
                                ->label('Button Text')
                                ->required()
                                ->placeholder('Click Here'),
                            Forms\Components\TextInput::make('link')
                                ->label('Button Link')
                                ->placeholder('/contact'),
                            Forms\Components\Select::make('style')
                                ->label('Button Style')
                                ->options([
                                    'primary' => 'Primary (filled)',
                                    'secondary' => 'Secondary (outline)',
                                    'accent' => 'Accent (highlight)',
                                ])
                                ->default('primary'),
                            Forms\Components\Toggle::make('visible')
                                ->label('Visible')
                                ->default(true),
                        ])
                        ->columns(4)
                        ->collapsible()
                        ->reorderable()
                        ->addActionLabel('Add Button')
                        ->itemLabel(fn (array $state): ?string => ($state['text'] ?? 'Button') . ' (' . ($state['style'] ?? 'primary') . ')')
                        ->columnSpanFull(),

                    'section_bg' => Forms\Components\Fieldset::make($label)
                        ->schema([
                            Forms\Components\ColorPicker::make($key . '.color')
                                ->label('Background Color'),
                            Forms\Components\FileUpload::make($key . '.image')
                                ->label('Background Image')
                                ->image()
                                ->directory(config('cms.media_upload_path', 'cms/media') . '/backgrounds'),
                            Forms\Components\Select::make($key . '.mode')
                                ->label('Image Mode')
                                ->options([
                                    'cover' => 'Cover (fill section)',
                                    'static' => 'Static (no scroll effect)',
                                    'parallax' => 'Parallax (fixed on scroll)',
                                    'repeat' => 'Repeat (tile pattern)',
                                ])
                                ->default('cover'),
                            Forms\Components\ColorPicker::make($key . '.overlay')
                                ->label('Overlay Color'),
                            Forms\Components\TextInput::make($key . '.overlay_opacity')
                                ->label('Overlay Opacity')
                                ->numeric()
                                ->minValue(0)
                                ->maxValue(1)
                                ->step(0.1)
                                ->placeholder('0.5'),
                        ])
                        ->columns(3)
                        ->columnSpanFull(),

                    'repeater' => Forms\Components\Repeater::make($key)
                        ->label($label)
                        ->schema(static::buildRepeaterSubFields($def))
                        ->columns(2)
                        ->collapsible()
                        ->reorderable()
                        ->cloneable()
                        ->addActionLabel('Add Item')
                        ->itemLabel(fn (array $state): ?string => $state[array_key_first($state)] ?? 'Item')
                        ->columnSpanFull(),

                    // Default: text input
                    default => Forms\Components\TextInput::make($key)
                        ->label($label)
                        ->placeholder($placeholder)
                        ->maxLength(500),
                };

                $groupComponents[] = $component;
            }

            $components[] = Forms\Components\Fieldset::make($groupName)
                ->schema($groupComponents)
                ->columns(2);
        }

        return $components;
    }

    /**
     * Build sub-field components for a repeater field definition.
     * Reads 'sub_fields' from the definition, or falls back to common patterns.
     */
    protected static function buildRepeaterSubFields(array $def): array
    {
        $subFields = $def['sub_fields'] ?? [];

        // If no sub_fields defined, try to infer from the key name
        if (empty($subFields)) {
            $key = strtolower($def['key'] ?? '');
            if (str_contains($key, 'team') || str_contains($key, 'member') || str_contains($key, 'employee')) {
                $subFields = [
                    ['key' => 'name', 'type' => 'text', 'label' => 'Name'],
                    ['key' => 'role', 'type' => 'text', 'label' => 'Role / Title'],
                    ['key' => 'image', 'type' => 'image', 'label' => 'Photo'],
                    ['key' => 'bio', 'type' => 'textarea', 'label' => 'Bio'],
                ];
            } elseif (str_contains($key, 'service')) {
                $subFields = [
                    ['key' => 'title', 'type' => 'text', 'label' => 'Title'],
                    ['key' => 'desc', 'type' => 'textarea', 'label' => 'Description'],
                    ['key' => 'icon', 'type' => 'text', 'label' => 'Icon (SVG or emoji)'],
                ];
            } elseif (str_contains($key, 'project') || str_contains($key, 'portfolio')) {
                $subFields = [
                    ['key' => 'title', 'type' => 'text', 'label' => 'Title'],
                    ['key' => 'desc', 'type' => 'textarea', 'label' => 'Description'],
                    ['key' => 'image', 'type' => 'image', 'label' => 'Image'],
                    ['key' => 'category', 'type' => 'text', 'label' => 'Category'],
                ];
            } elseif (str_contains($key, 'product')) {
                $subFields = [
                    ['key' => 'name', 'type' => 'text', 'label' => 'Name'],
                    ['key' => 'desc', 'type' => 'textarea', 'label' => 'Description'],
                    ['key' => 'price', 'type' => 'text', 'label' => 'Price'],
                    ['key' => 'image', 'type' => 'image', 'label' => 'Image'],
                ];
            } elseif (str_contains($key, 'testimonial') || str_contains($key, 'review')) {
                $subFields = [
                    ['key' => 'name', 'type' => 'text', 'label' => 'Name'],
                    ['key' => 'text', 'type' => 'textarea', 'label' => 'Testimonial'],
                    ['key' => 'role', 'type' => 'text', 'label' => 'Role / Company'],
                    ['key' => 'image', 'type' => 'image', 'label' => 'Photo'],
                ];
            } elseif (str_contains($key, 'faq')) {
                $subFields = [
                    ['key' => 'question', 'type' => 'text', 'label' => 'Question'],
                    ['key' => 'answer', 'type' => 'textarea', 'label' => 'Answer'],
                ];
            } elseif (str_contains($key, 'feature')) {
                $subFields = [
                    ['key' => 'title', 'type' => 'text', 'label' => 'Title'],
                    ['key' => 'desc', 'type' => 'textarea', 'label' => 'Description'],
                    ['key' => 'icon', 'type' => 'text', 'label' => 'Icon'],
                ];
            } else {
                // Generic fallback
                $subFields = [
                    ['key' => 'title', 'type' => 'text', 'label' => 'Title'],
                    ['key' => 'content', 'type' => 'textarea', 'label' => 'Content'],
                    ['key' => 'image', 'type' => 'image', 'label' => 'Image'],
                ];
            }
        }

        $components = [];
        foreach ($subFields as $sub) {
            $subKey = $sub['key'];
            $subLabel = $sub['label'] ?? Page::keyToLabel($subKey);
            $subType = $sub['type'] ?? 'text';

            $components[] = match ($subType) {
                'textarea' => Forms\Components\Textarea::make($subKey)
                    ->label($subLabel)
                    ->rows(2),
                'image' => Forms\Components\FileUpload::make($subKey)
                    ->label($subLabel)
                    ->image()
                    ->directory(config('cms.media_upload_path', 'cms/media'))
                    ->imageEditor()
                    ->imagePreviewHeight('100'),
                'richtext' => Forms\Components\RichEditor::make($subKey)
                    ->label($subLabel)
                    ->columnSpanFull(),
                'url' => Forms\Components\TextInput::make($subKey)
                    ->label($subLabel)
                    ->placeholder('https://'),
                'number' => Forms\Components\TextInput::make($subKey)
                    ->label($subLabel)
                    ->numeric(),
                'color' => Forms\Components\ColorPicker::make($subKey)
                    ->label($subLabel),
                'toggle' => Forms\Components\Toggle::make($subKey)
                    ->label($subLabel),
                default => Forms\Components\TextInput::make($subKey)
                    ->label($subLabel)
                    ->maxLength(500),
            };
        }

        return $components;
    }

    public static function table(Table $table): Table
    {
        return $table
            ->columns([
                Tables\Columns\TextColumn::make('title')
                    ->searchable()
                    ->sortable(),

                Tables\Columns\TextColumn::make('slug')
                    ->searchable(),

                Tables\Columns\TextColumn::make('page_type')
                    ->label('Type')
                    ->badge()
                    ->color(fn (?string $state): string => match ($state) {
                        'post' => 'info',
                        default => 'gray',
                    }),

                Tables\Columns\TextColumn::make('template')
                    ->badge()
                    ->color(fn (string $state): string => match ($state) {
                        'custom' => 'info',
                        'default' => 'gray',
                        default => 'info',
                    }),

                Tables\Columns\TextColumn::make('status')
                    ->badge()
                    ->color(fn (string $state): string => match ($state) {
                        'published' => 'success',
                        'draft' => 'gray',
                        default => 'gray',
                    }),

                Tables\Columns\TextColumn::make('fields_count')
                    ->label('Fields')
                    ->getStateUsing(fn (Page $record): int => count($record->field_definitions ?? []))
                    ->badge()
                    ->color('primary'),

                Tables\Columns\TextColumn::make('sort_order')
                    ->sortable(),

                Tables\Columns\TextColumn::make('updated_at')
                    ->dateTime()
                    ->sortable(),
            ])
            ->filters([
                Tables\Filters\SelectFilter::make('page_type')
                    ->label('Type')
                    ->options([
                        'page' => 'Page',
                        'post' => 'Blog Post',
                    ]),
                Tables\Filters\SelectFilter::make('status')
                    ->options([
                        'draft' => 'Draft',
                        'published' => 'Published',
                    ]),
                Tables\Filters\SelectFilter::make('template')
                    ->options(fn () => Page::getAvailableTemplates()),
            ])
            ->actions([
                Tables\Actions\EditAction::make(),
                Tables\Actions\Action::make('view_live')
                    ->label('View')
                    ->icon('heroicon-o-eye')
                    ->url(function (Page $record): string {
                        $homePageId = \CreativeCatCo\GkCmsCore\Models\Setting::get('home_page_id');
                        $isHome = ($homePageId && $record->id == $homePageId) || (!$homePageId && $record->slug === 'home');
                        return url($isHome ? '/' : $record->slug);
                    })
                    ->openUrlInNewTab(),
                Tables\Actions\Action::make('open_builder')
                    ->label('Builder')
                    ->icon('heroicon-o-wrench-screwdriver')
                    ->url(function (Page $record): string {
                        $homePageId = \CreativeCatCo\GkCmsCore\Models\Setting::get('home_page_id');
                        $isHome = ($homePageId && $record->id == $homePageId) || (!$homePageId && $record->slug === 'home');
                        return url(($isHome ? '/' : $record->slug) . '?edit=true');
                    })
                    ->openUrlInNewTab()
                    ->color('primary'),
                Tables\Actions\DeleteAction::make(),
            ])
            ->bulkActions([
                Tables\Actions\BulkActionGroup::make([
                    Tables\Actions\DeleteBulkAction::make(),
                ]),
            ])
            ->reorderable('sort_order')
            ->defaultSort('sort_order');
    }

    public static function getRelations(): array
    {
        return [];
    }

    public static function getPages(): array
    {
        return [
            'index' => Pages\ListPages::route('/'),
            'create' => Pages\CreatePage::route('/create'),
            'edit' => Pages\EditPage::route('/{record}/edit'),
        ];
    }
}
